            <style type="text/css">

                .menu-o-proekte {

                }

                /* .hoverIGATION */
                .menu-o-proekte,
                .menu-o-proekte:after,
                .menu-o-proekte:before {
                  transition: all .5s;
                }
                .menu-o-proekte:hover {
                  color: #FFFFFF;  
                }


                /* stroke */
                .menu-o-proekte.stroke,
                .menu-o-proekte.fill {
                  position: relative;
                }
                .menu-o-proekte.stroke:after,
                .menu-o-proekte.fill:after {
                  position: absolute;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  margin: auto;
                  width: 0%;
                  content: '.';
                  color: transparent;
                  background: #FF196C;
                  height: 1px;
                }

                .menu-o-proekte.stroke:hover:after {
                  width: 100%;
                }

                .menu-o-proekte.fill {
                  transition: all 2s;
                }

                .menu-o-proekte.fill:after {
                  text-align: left;
                  content: '.';
                  margin: 0;
                  opacity: 0;
                }
                .menu-o-proekte.fill:hover {
                  color: #FFFFFF;
                  z-index: 1;
                }
                .menu-o-proekte.fill:hover:after {
                  z-index: -10;
                  animation: fill 1s forwards;
                  -webkit-animation: fill 1s forwards;
                  -moz-animation: fill 1s forwards;
                  opacity: 1;
                }

                /* Circle */
                .menu-o-proekte.circle {
                  position: relative;
                  overflow: hidden;
                  z-index: 1;
                }
                .menu-o-proekte.circle:after {
                  display: block;
                  position: absolute;
                  margin: 0;
                  top: 0;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  content: '.';
                  color: transparent;
                  width: 1px;
                  height: 1px;
                  border-radius: 50%;
                  background: transparent;
                }
                .menu-o-proekte.circle:hover:after {
                  -webkit-animation: circle 1.5s ease-in forwards;
                }

                /* SHIFT */
                .menu-o-proekte.shift {
                  position:relative;
                  z-index: 1;
                }
                .menu-o-proekte.shift:hover {
                  color: #FFFFFF;
                }
                .menu-o-proekte.shift:after {
                  display: block;
                  position: absolute;
                  top: 0;
                  left: 0;
                  bottom: 0;
                  right: 0;
                  margin: auto;
                  width: 100%;
                  height: 1px;
                  content: '.';
                  color: transparent;
                  background: #FF196C;
                  visibility: none;
                  opacity: 0;
                  z-index: -1;
