                  z-index: -10;
                  animation: fill 1s forwards;
                  -webkit-animation: fill 1s forwards;
                  -moz-animation: fill 1s forwards;
                  opacity: 1;
                }

                /* Circle */
                .menu-dokumenti.circle {
                  position: relative;
                  overflow: hidden;
                  z-index: 1;
                }
                .menu-dokumenti.circle:after {
                  display: block;
                  position: absolute;
                  margin: 0;
                  top: 0;
                  bottom: 0;
                  left: 0;
                  right: 0;
                  content: '.';
                  color: transparent;
                  width: 1px;
                  height: 1px;
                  border-radius: 50%;
                  background: transparent;
                }
                .menu-dokumenti.circle:hover:after {
