                  top: 0;
                  left: 0;
                  bottom: 0;
                  right: 0;
                  margin: auto;
                  width: 100%;
                  height: 1px;
                  content: '.';
                  color: transparent;
                  background: #D4145A;
                  visibility: none;
                  opacity: 0;
                  z-index: -1;
                  border-radius: 12px;
                }
                .menu-dokumenti.shift:hover:after {
                  opacity: 1;
                  visibility: visible;
                  height: 100%;
                }



